css:
.thermal-receipt {
    width: 80mm;
    max-width: 80mm;
    font-family: Arial, sans-serif;
    font-size: 11px;
    color: #000;
    padding: 0;
    margin: 0;
}

.receipt-header {
    text-align: center;
    margin-bottom: 6px;
}

.logo-box {
    font-size: 19px;
    font-weight: 900;
    letter-spacing: 1.5px;
    line-height: 1.2;
}

.shop-name {
    font-size: 12px;
    font-weight: 700;
    margin-top: 3px;
}

.shop-info {
    font-size: 10px;
    margin-top: 2px;
}

.receipt-label {
    font-size: 11px;
    font-weight: 700;
    margin-top: 5px;
    text-transform: uppercase;
}

.receipt-info {
    font-size: 10.5px;
    line-height: 1.45;
}

.receipt-info div {
    display: flex;
    justify-content: space-between;
    gap: 8px;
}

.receipt-info span {
    font-weight: 600;
}

.receipt-info strong {
    text-align: right;
    font-weight: 700;
}

.receipt-items {
    width: 100%;
    border-collapse: collapse;
    font-size: 10.5px;
}

.receipt-items th {
    text-align: left;
    border-bottom: 1px dashed #000;
    padding: 3px 0;
    font-weight: 700;
}

.receipt-items td {
    padding: 3px 0;
    vertical-align: top;
}

.receipt-items th:nth-child(2),
.receipt-items td:nth-child(2),
.receipt-items th:nth-child(3),
.receipt-items td:nth-child(3),
.receipt-items th:nth-child(4),
.receipt-items td:nth-child(4) {
    text-align: right;
}

.receipt-items td:first-child {
    width: 42%;
    word-break: break-word;
}

.receipt-summary {
    font-size: 11px;
}

.summary-row {
    display: flex;
    justify-content: space-between;
    padding: 2px 0;
}

.grand-total {
    font-size: 14px;
    font-weight: 900;
    padding: 4px 0;
}

.payment-breakdown {
    font-size: 11px;
}

.section-title {
    font-size: 11px;
    font-weight: 800;
    margin-bottom: 3px;
    text-transform: uppercase;
}

.payment-row {
    display: flex;
    justify-content: space-between;
    padding: 2px 0;
}

.receipt-footer {
    text-align: center;
    font-size: 10.5px;
    margin-top: 8px;
}

.thanks {
    font-weight: 800;
}

.powered {
    margin-top: 3px;
    font-size: 9.5px;
}

hr {
    border: none;
    border-top: 1px dashed #000;
    margin: 6px 0;
}

@media print {
    @page {
        size: 80mm auto;
        margin: 3mm;
    }

    body {
        margin: 0;
        padding: 0;
    }
}
